import React, { useState } from "react";
import "./CalendarPage.scss";
import { Course } from "../../Types/course";
import { Deadline } from "../../Types/deadline"; // Используем один тип везде
import { DeadlineModal } from "../DeadlineModal/DeadlineModal"; // ПРОВЕРЬ ПУТЬ к файлу!
import { Sidebar } from "../../сomponents/Sidebar";

interface CalendarPageProps {
  currentPage: string;
  deadlines: Deadline[]; // Поправили имя типа
  courses: Course[];
  onNavigate: (page: string) => void;
  onLogout: () => void;
  onAddDeadline: (deadline: Omit<Deadline, "id">) => void;
}

const TopBar: React.FC<{ userName: string }> = ({ userName }) => {
  return (
    <div className="topbar">
      <div className="topbar__content">
        <h1 className="topbar__title">Academic Calendar</h1>
        <div className="topbar__user">
          <span className="topbar__user-name">Welcome {userName}!</span>
        </div>
      </div>
    </div>
  );
};

// !!! ВАЖНО: Я удалил отсюда старый const DeadlineModal, 
// который вызывал ошибку Duplicate declaration !!!

export function CalendarPage({
  currentPage,
  deadlines,
  courses,
  onNavigate,
  onLogout,
  onAddDeadline,
}: CalendarPageProps) {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [showAddModal, setShowAddModal] = useState(false);

  const getCourseById = (courseId: string) => {
    return courses.find((c) => c.id === courseId);
  };

  const monthNames = [
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December"
  ];

  const daysInMonth = (date: Date) => new Date(date.getFullYear(), date.getMonth() + 1, 0).getDate();
  const firstDayOfMonth = (date: Date) => new Date(date.getFullYear(), date.getMonth(), 1).getDay();

  const previousMonth = () => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1));
  const nextMonth = () => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1));

  const getDeadlinesForDate = (day: number) => {
    const date = new Date(currentDate.getFullYear(), currentDate.getMonth(), day);
    date.setHours(0, 0, 0, 0);
    return deadlines.filter((d) => {
      const dDate = new Date(d.dueDate);
      dDate.setHours(0, 0, 0, 0);
      return dDate.getTime() === date.getTime();
    });
  };

  const isToday = (day: number) => {
    const today = new Date();
    return day === today.getDate() && currentDate.getMonth() === today.getMonth() && currentDate.getFullYear() === today.getFullYear();
  };

  const days = [];
  const totalDays = daysInMonth(currentDate);
  const startDay = firstDayOfMonth(currentDate);
  for (let i = 0; i < startDay; i++) days.push(null);
  for (let day = 1; day <= totalDays; day++) days.push(day);

  return (
    <div className="calendar-page">
      <Sidebar currentPage={currentPage} onNavigate={onNavigate} onLogout={onLogout} />
      <div className="main-content">
        <TopBar userName="" />
        <main className="content">
          <div className="calendar-container">
            <div className="calendar">
              <div className="calendar__header">
                <h2 className="calendar__title">{monthNames[currentDate.getMonth()]} {currentDate.getFullYear()}</h2>
                <div className="calendar__controls">
                  <button onClick={previousMonth} className="calendar__nav-btn">‹</button>
                  <button onClick={() => setCurrentDate(new Date())} className="btn btn--today">Today</button>
                  <button onClick={nextMonth} className="calendar__nav-btn">›</button>
                  <button onClick={() => setShowAddModal(true)} className="btn btn--add">+ Add Deadline</button>
                </div>
              </div>
              <div className="calendar__grid">
                {["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"].map(day => (
                  <div key={day} className="calendar__day-header">{day}</div>
                ))}
                {days.map((day, index) => (
                  day === null ? (
                    <div key={`empty-${index}`} className="calendar__day calendar__day--empty" />
                  ) : (
                    <div key={day} className={`calendar__day ${isToday(day) ? "calendar__day--today" : ""}`}>
                      <div className={`calendar__day-number ${isToday(day) ? "calendar__day-number--today" : ""}`}>{day}</div>
                      <div className="calendar__deadlines">
                        {getDeadlinesForDate(day).slice(0, 3).map(d => (
                          <div key={d.id} className="calendar__deadline-item" style={{ color: getCourseById(d.courseId)?.color }}>
                            {d.taskName}
                          </div>
                        ))}
                      </div>
                    </div>
                  )
                ))}
              </div>
            </div>
          </div>
        </main>
      </div>

      {/* Используем нашу импортированную модалку */}
      {showAddModal && (
        <DeadlineModal
          courses={courses}
          onSave={onAddDeadline}
          onClose={() => setShowAddModal(false)}
        />
      )}
    </div>
  );
}
